SELECT t.year, t.tmid, t.name, t.gf, COUNT(DISTINCT a.coachid) AS all_star_coaches FROM teams AS t JOIN teamvsteam AS tvt ON t.tmid = tvt.tmid AND t.year = tvt.year JOIN coaches AS c ON t.tmid = c.tmid JOIN awardscoaches AS a ON c.coachid = a.coachid JOIN abbrev AS ab ON t.confid = ab.code WHERE (t.year >= 2006) AND (ab.fullname = 'Eastern Conference') GROUP BY t.year, t.tmid, t.name, t.gf HAVING (COUNT(DISTINCT a.coachid) >= 1)
